// This array will store our final structured outputs
const results = [];

// 1. Loop through all incoming items safely using n8n's standard collection syntax
for (const item of $input.all()) {

  // 2. Safely capture the data from the Gemini node output fields
  // Try extracting standard message model payload outputs (text, content, or general output)
  let content = item.json.text || item.json.content || item.json.output || "";

  // 3. Defensive Check: If content is an object or array instead of a string, stringify it
  if (typeof content !== 'string') {
    content = JSON.stringify(content);
  }

  // 4. Safely trim trailing/leading spaces
  let jsonStr = content.trim();

  // 5. Clean off Markdown wrappers (like ```json ... ```) if Gemini includes them
  if (jsonStr.startsWith('```json')) {
    jsonStr = jsonStr.substring(7, jsonStr.length).trim();
  } else if (jsonStr.startsWith('```')) {
    jsonStr = jsonStr.substring(3, jsonStr.length).trim();
  }

  if (jsonStr.endsWith('```')) {
    jsonStr = jsonStr.substring(0, jsonStr.length - 3).trim();
  }

  // 6. Regex extract fallback: Isolate only the true JSON curly block {} inside text string
  const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    jsonStr = jsonMatch[0];
  }

  // 7. Safe JSON Parsing Block
  let parsed;
  try {
    // If the string is completely empty, provide an empty fallback object to avoid parsing crash
    parsed = jsonStr ? JSON.parse(jsonStr) : {};
  } catch (e) {
    // If parsing fails, don't crash the workflow. Log the raw data into an error property.
    results.push({ 
      json: { 
        error: 'Failed to parse JSON string securely', 
        raw_content: content 
      } 
    });
    continue;
  }

  // 8. Output generation: Add structured values downstream to tables or sheets
  results.push({
    json: {
      companyName: parsed.companyName || parsed["Company Name"] || "Not Specified",
      skillsRequired: parsed.skillsRequired || parsed["Key Skills Required"] || parsed["skills"] || "Not Specified",
      location: parsed.location || parsed["Location"] || "Hyderabad",
      summary: parsed.summary || parsed["Brief 2-sentence summary of the job responsibilities"] || "No summary provided"
    }
  });
}

// Return the cleaned list of items to n8n
return results;
